import React, { useState, useEffect } from 'react';
import api from '../services/api';
import { toast } from 'react-toastify';
import jsPDF from 'jspdf';
import 'jspdf-autotable';

const Reports = () => {
  const [loading, setLoading] = useState(true);
  const [summary, setSummary] = useState({
    savings: { total: 0, count: 0 },
    loans: { total: 0, count: 0 },
    repayments: { total: 0, count: 0 }
  });
  const [reportType, setReportType] = useState('savings');
  const [detailedData, setDetailedData] = useState([]);
  const [fetchingDetailed, setFetchingDetailed] = useState(false);

  useEffect(() => {
    fetchSummary();
  }, []);

  useEffect(() => {
    fetchDetailedData();
  }, [reportType]);

  const fetchSummary = async () => {
    try {
      setLoading(true);
      const [savingsRes, loansRes, repaymentsRes] = await Promise.all([
        api.get('/admin/reports/savings'),
        api.get('/admin/reports/loans'),
        api.get('/admin/reports/repayments')
      ]);

      setSummary({
        savings: savingsRes.data?.data || savingsRes.data || { total: 0, count: 0 },
        loans: {
          total: (loansRes.data?.data || loansRes.data || []).reduce((acc, curr) => acc + curr.total, 0),
          count: (loansRes.data?.data || loansRes.data || []).reduce((acc, curr) => acc + curr.count, 0)
        },
        repayments: repaymentsRes.data?.data || repaymentsRes.data || { total: 0, count: 0 }
      });
    } catch (err) {
      console.error(err);
      toast.error('Failed to fetch summary data');
    } finally {
      setLoading(false);
    }
  };

  const fetchDetailedData = async () => {
    try {
      setFetchingDetailed(true);
      const res = await api.get(`/admin/reports/${reportType}/detailed`);
      setDetailedData(res.data?.data || res.data || []);
    } catch (err) {
      console.error(err);
      toast.error(`Failed to fetch detailed ${reportType} data`);
    } finally {
      setFetchingDetailed(false);
    }
  };

  const downloadPDF = () => {
    const doc = new jsPDF();
    const title = `${reportType.charAt(0).toUpperCase() + reportType.slice(1)} Report`;
    const date = new Date().toLocaleString();

    doc.setFontSize(20);
    doc.text('Harari Sacco Management System', 105, 15, { align: 'center' });
    doc.setFontSize(16);
    doc.text(title, 105, 25, { align: 'center' });
    doc.setFontSize(10);
    doc.text(`Generated on: ${date}`, 105, 32, { align: 'center' });

    const tableColumn = reportType === 'loans'
      ? ["Member", "Amount", "Status", "Date"]
      : ["Member", "Amount", "Date"];

    const tableRows = detailedData.map(item => {
      const row = [
        item.memberId?.fullName || 'N/A',
        item.amount.toLocaleString(),
        reportType === 'loans' ? item.status : new Date(item.date || item.createdAt).toLocaleDateString(),
      ];
      if (reportType === 'loans') {
        row.push(new Date(item.createdAt).toLocaleDateString());
      }
      return row;
    });

    doc.autoTable({
      head: [tableColumn],
      body: tableRows,
      startY: 40,
      theme: 'grid',
      headStyles: { fillColor: [99, 102, 241] }
    });

    doc.save(`${reportType}_report_${new Date().getTime()}.pdf`);
    toast.success('PDF Downloaded');
  };

  const downloadCSV = () => {
    if (detailedData.length === 0) {
      toast.warning('No data to export');
      return;
    }

    const headers = reportType === 'loans'
      ? ["Member", "Email", "Amount", "Status", "Date"]
      : ["Member", "Email", "Amount", "Date"];

    const csvRows = [
      headers.join(','),
      ...detailedData.map(item => {
        const row = [
          `"${item.memberId?.fullName || 'N/A'}"`,
          `"${item.memberId?.email || 'N/A'}"`,
          item.amount,
          reportType === 'loans' ? item.status : `"${new Date(item.date || item.createdAt).toLocaleDateString()}"`,
        ];
        if (reportType === 'loans') {
          row.push(`"${new Date(item.createdAt).toLocaleDateString()}"`);
        }
        return row.join(',');
      })
    ];

    const csvString = csvRows.join('\n');
    const blob = new Blob([csvString], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    const url = URL.createObjectURL(blob);
    link.setAttribute("href", url);
    link.setAttribute("download", `${reportType}_report_${new Date().getTime()}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    toast.success('CSV Downloaded');
  };

  if (loading) {
    return (
      <div className="loading-container">
        <div className="loading-spinner"></div>
        <p style={{ marginTop: '1rem', color: 'var(--text-secondary)' }}>Loading reports...</p>
      </div>
    );
  }

  return (
    <div className="fade-in">
      <div className="flex-between mb-6">
        <div>
          <h2 className="page-title">📑 Reports & Analytics</h2>
          <p style={{ color: 'var(--text-secondary)', fontSize: '0.875rem' }}>
            Generate and export comprehensive financial reports
          </p>
        </div>
        <button className="btn btn-secondary" onClick={fetchSummary}>
          🔄 Refresh Data
        </button>
      </div>

      <div className="card-row">
        <div className="stats-card">
          <div className="stats-card-header">
            <div className="stats-info">
              <p className="stats-title">Total Savings</p>
              <h3 className="stats-value">{summary.savings.total.toLocaleString()} ETB</h3>
            </div>
            <div className="stats-icon" style={{ background: 'rgba(16, 185, 129, 0.1)', color: 'var(--success)' }}>
              💰
            </div>
          </div>
          <div className="stats-footer">
            From {summary.savings.count} transactions
          </div>
        </div>

        <div className="stats-card">
          <div className="stats-card-header">
            <div className="stats-info">
              <p className="stats-title">Total Loans</p>
              <h3 className="stats-value">{summary.loans.total.toLocaleString()} ETB</h3>
            </div>
            <div className="stats-icon" style={{ background: 'rgba(99, 102, 241, 0.1)', color: 'var(--primary)' }}>
              🏦
            </div>
          </div>
          <div className="stats-footer">
            {summary.loans.count} loans issued
          </div>
        </div>

        <div className="stats-card">
          <div className="stats-card-header">
            <div className="stats-info">
              <p className="stats-title">Total Repayments</p>
              <h3 className="stats-value">{summary.repayments.total.toLocaleString()} ETB</h3>
            </div>
            <div className="stats-icon" style={{ background: 'rgba(245, 158, 11, 0.1)', color: 'var(--warning)' }}>
              📈
            </div>
          </div>
          <div className="stats-footer">
            From {summary.repayments.count} payments
          </div>
        </div>
      </div>

      <div className="card mb-6">
        <div className="flex-between mb-4">
          <h3 style={{ margin: 0 }}>📊 Report Generator</h3>
          <div style={{ display: 'flex', gap: '0.5rem' }}>
            <button className="btn btn-primary" onClick={downloadPDF}>
              📄 Download PDF
            </button>
            <button className="btn btn-secondary" onClick={downloadCSV}>
              📁 Download CSV
            </button>
          </div>
        </div>

        <div style={{ display: 'flex', gap: '1rem', marginBottom: '1.5rem' }}>
          <div style={{ flex: 1 }}>
            <label style={{ display: 'block', marginBottom: '0.5rem', fontSize: '0.875rem', color: 'var(--text-secondary)' }}>
              Select Report Type
            </label>
            <select
              className="input"
              value={reportType}
              onChange={(e) => setReportType(e.target.value)}
            >
              <option value="savings">Savings Report</option>
              <option value="loans">Loans Report</option>
              <option value="repayments">Repayments Report</option>
            </select>
          </div>
        </div>

        <div className="table-container">
          {fetchingDetailed ? (
            <div style={{ padding: '2rem', textAlign: 'center' }}>
              <div className="loading-spinner" style={{ margin: '0 auto' }}></div>
              <p style={{ marginTop: '1rem', color: 'var(--text-secondary)' }}>Fetching detailed data...</p>
            </div>
          ) : (
            <table>
              <thead>
                <tr>
                  <th>Member</th>
                  <th>Amount</th>
                  {reportType === 'loans' ? <th>Status</th> : <th>Date</th>}
                  {reportType === 'loans' && <th>Date</th>}
                </tr>
              </thead>
              <tbody>
                {detailedData.length > 0 ? (
                  detailedData.slice(0, 10).map((item, index) => (
                    <tr key={index}>
                      <td>
                        <div style={{ fontWeight: 600 }}>{item.memberId?.fullName || 'N/A'}</div>
                        <div style={{ fontSize: '0.75rem', color: 'var(--text-secondary)' }}>{item.memberId?.email || 'N/A'}</div>
                      </td>
                      <td>{item.amount.toLocaleString()} ETB</td>
                      {reportType === 'loans' ? (
                        <td>
                          <span className={`status-badge status-${item.status}`}>
                            {item.status}
                          </span>
                        </td>
                      ) : (
                        <td>{new Date(item.date || item.createdAt).toLocaleDateString()}</td>
                      )}
                      {reportType === 'loans' && (
                        <td>{new Date(item.createdAt).toLocaleDateString()}</td>
                      )}
                    </tr>
                  ))
                ) : (
                  <tr>
                    <td colSpan={reportType === 'loans' ? 4 : 3} style={{ textAlign: 'center', padding: '2rem', color: 'var(--text-secondary)' }}>
                      No data available for this report type
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          )}
          {detailedData.length > 10 && (
            <div style={{ padding: '1rem', textAlign: 'center', borderTop: '1px solid var(--border)', fontSize: '0.875rem', color: 'var(--text-secondary)' }}>
              Showing first 10 entries. Download full report for all data.
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Reports;
